        )

    cleaned, errors = validate_registration_payload(payload)

    email_for_limit = cleaned.email_normalized if cleaned else rough_email_key(payload.get("email"))
    if email_for_limit:
        allowed, retry_after = rate_limiter.check(rate_key(f"email:{email_for_limit}"), 3, 60 * 60)
        if not allowed:
            return rate_limit_response(retry_after)

    username_for_limit = cleaned.username_normalized if cleaned else rough_email_key(payload.get("username"))
    if username_for_limit:
        allowed, retry_after = rate_limiter.check(rate_key(f"username:{username_for_limit}"), 5, 60 * 60)
        if not allowed:
            return rate_limit_response(retry_after)

    if cleaned and ENABLE_HIBP_CHECK and not password_too_large(cleaned.password):
        try:
            pwned_count = await hibp_pwned_password_count(cleaned.password)
            if pwned_count > 0:
                errors.append({
                    "field": "password",
                    "code": "breached_password",
                    "message": "Password appears in known breach data and cannot be used.",
                })
        except Exception:
            if HIBP_FAIL_CLOSED:
                errors.append({
                    "field": "password",
                    "code": "breach_check_unavailable",
                    "message": "Password breach check is temporarily unavailable.",
                })

    if errors:
        return error_response(status.HTTP_422_UNPROCESSABLE_ENTITY, errors)

    assert cleaned is not None

    password_hash = hash_password(cleaned.password)

    try:
        insert_user(cleaned, password_hash)
    except sqlite3.Error:
        await sleep_until_minimum(started)
        return error_response(
            status.HTTP_503_SERVICE_UNAVAILABLE,
            [{"field": "server", "code": "temporarily_unavailable", "message": "Registration is temporarily unavailable."}],
        )

    await sleep_until_minimum(started)

    # Same response for new accounts and duplicate email/username attempts.
    return JSONResponse(
        status_code=status.HTTP_202_ACCEPTED,
        content={"ok": True, "message": "Registration request accepted."},
    )


def validate_registration_payload(payload: dict[str, Any]) -> tuple[CleanRegistration | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    allowed_fields = {"email", "username", "password", "display_name"}

    for field in sorted(set(payload) - allowed_fields):
        errors.append({
            "field": field,
            "code": "unexpected_field",
            "message": "Unexpected field is not allowed.",
        })

    for field in sorted(allowed_fields):
        if field not in payload:
            errors.append({
                "field": field,
                "code": "required",
                "message": "Field is required.",
            })

    email, email_norm = validate_email_field(payload.get("email"), errors)
    username, username_norm = validate_username_field(payload.get("username"), errors)
    display_name = validate_display_name_field(payload.get("display_name"), errors)
    password = validate_password_field(payload.get("password"), username_norm, email_norm, display_name, errors)

    if errors or not all([email, email_norm, username, username_norm, display_name, password]):
        return None, errors

    return CleanRegistration(
        email=email,
        email_normalized=email_norm,
        username=username,
        username_normalized=username_norm,
        display_name=display_name,
        password=password,
    ), errors


def validate_email_field(value: Any, errors: list[dict[str, str]]) -> tuple[str | None, str | None]:
    if "email" not in errors and not isinstance(value, str):
        errors.append({"field": "email", "code": "invalid_type", "message": "Email must be a string."})
        return None, None

    raw = value
    stripped = raw.strip()
    normalized_input = unicodedata.normalize("NFKC", stripped)

    if not stripped:
        errors.append({"field": "email", "code": "empty", "message": "Email is required."})
        return None, None

    if raw != stripped:
        errors.append({"field": "email", "code": "surrounding_whitespace", "message": "Email must not contain leading or trailing whitespace."})

    if CONTROL_OR_INVISIBLE_RE.search(normalized_input) or "\r" in normalized_input or "\n" in normalized_input:
        errors.append({"field": "email", "code": "invalid_characters", "message": "Email contains invalid control or invisible characters."})

    if any(ch.isspace() for ch in normalized_input):
        errors.append({"field": "email", "code": "whitespace", "message": "Email must not contain whitespace."})

    if len(normalized_input.encode("utf-8")) > 254:
        errors.append({"field": "email", "code": "too_long", "message": "Email must be at most 254 bytes."})

    if normalized_input.count("@") != 1:
        errors.append({"field": "email", "code": "invalid_format", "message": "Email must contain exactly one @ sign."})
        return None, None

    try:
        parsed = validate_email(
            normalized_input,
            allow_smtputf8=False,
            check_deliverability=CHECK_EMAIL_DELIVERABILITY,
            allow_empty_local=False,
        )
    except EmailNotValidError:
        errors.append({"field": "email", "code": "invalid_format", "message": "Email address is invalid or undeliverable."})
        return None, None

    local = parsed.local_part
    ascii_domain = parsed.ascii_domain.casefold().rstrip(".")
    domain = parsed.domain.casefold().rstrip(".")

    if len(local.encode("utf-8")) > 64:
        errors.append({"field": "email", "code": "local_part_too_long", "message": "Email local part is too long."})

    if local.startswith(".") or local.endswith(".") or ".." in local:
        errors.append({"field": "email", "code": "invalid_local_part", "message": "Email local part has invalid dot placement."})

    try:
        ipaddress.ip_address(ascii_domain.strip("[]"))
        errors.append({"field": "email", "code": "ip_domain_not_allowed", "message": "Email domain must not be an IP address."})
    except ValueError:
        pass

    labels = ascii_domain.split(".")
    if len(labels) < 2:
        errors.append({"field": "email", "code": "domain_missing_suffix", "message": "Email domain must include a public suffix."})

    if any(not label or len(label) > 63 for label in labels):
        errors.append({"field": "email", "code": "invalid_domain_label", "message": "Email domain has an invalid label."})

    tld = labels[-1] if labels else ""
    if tld in BLOCKED_EMAIL_TLDS:
        errors.append({"field": "email", "code": "blocked_domain", "message": "Email domain is not allowed."})

    if domain_is_blocked(ascii_domain, DISPOSABLE_EMAIL_DOMAINS) or domain_is_blocked(domain, DISPOSABLE_EMAIL_DOMAINS):
        errors.append({"field": "email", "code": "disposable_email", "message": "Disposable email addresses are not allowed."})

    canonical = f"{local.casefold()}@{ascii_domain}"
    return canonical, canonical


def validate_username_field(value: Any, errors: list[dict[str, str]]) -> tuple[str | None, str | None]:
    if not isinstance(value, str):
        errors.append({"field": "username", "code": "invalid_type", "message": "Username must be a string."})
        return None, None

    raw = value
    username = unicodedata.normalize("NFKC", raw.strip())

    if not username:
        errors.append({"field": "username", "code": "empty", "message": "Username is required."})
        return None, None

    if raw != raw.strip():
        errors.append({"field": "username", "code": "surrounding_whitespace", "message": "Username must not contain leading or trailing whitespace."})

    if CONTROL_OR_INVISIBLE_RE.search(username):
        errors.append({"field": "username", "code": "invalid_characters", "message": "Username contains control or invisible characters."})

    if len(username) < 3:
        errors.append({"field": "username", "code": "too_short", "message": "Username must be at least 3 characters."})

    if len(username) > 30:
        errors.append({"field": "username", "code": "too_long", "message": "Username must be at most 30 characters."})

    if not USERNAME_RE.fullmatch(username):
        errors.append({
            "field": "username",
            "code": "invalid_format",
            "message": "Username must use ASCII letters, numbers, dots, underscores, or hyphens, and start/end with a letter or number.",
        })

    if re.search(r"[._-]{2,}", username):
        errors.append({"field": "username", "code": "repeated_separators", "message": "Username must not contain repeated separators."})

    username_norm = username.casefold()
    skeleton = username_skeleton(username_norm)

    if constant_time_member(username_norm, RESERVED_USERNAMES) or constant_time_member(skeleton, RESERVED_USERNAMES):
        errors.append({"field": "username", "code": "reserved", "message": "Username is reserved."})

    for term in BANNED_USERNAME_TERMS:
        if term and term in skeleton:
            errors.append({"field": "username", "code": "blocked_content", "message": "Username contains blocked content."})
            break

    return username, username_norm


def validate_display_name_field(value: Any, errors: list[dict[str, str]]) -> str | None:
    if not isinstance(value, str):
        errors.append({"field": "display_name", "code": "invalid_type", "message": "Display name must be a string."})
        return None

    display_name = unicodedata.normalize("NFKC", value)
    display_name = re.sub(r"\s+", " ", display_name).strip()

    if not display_name:
        errors.append({"field": "display_name", "code": "empty", "message": "Display name is required."})
        return None

    if CONTROL_OR_INVISIBLE_RE.search(display_name):
        errors.append({"field": "display_name", "code": "invalid_characters", "message": "Display name contains control or invisible characters."})

    if len(display_name) > 80:
        errors.append({"field": "display_name", "code": "too_long", "message": "Display name must be at most 80 characters."})

    if len(display_name.encode("utf-8")) > 160:
        errors.append({"field": "display_name", "code": "too_long_bytes", "message": "Display name is too long in bytes."})

    if "<" in display_name or ">" in display_name:
        errors.append({"field": "display_name", "code": "html_not_allowed", "message": "Display name must not contain HTML."})

    return html.escape(display_name, quote=True)


def validate_password_field(
    value: Any,
    username_norm: str | None,
    email_norm: str | None,
    display_name: str | None,
    errors: list[dict[str, str]],
) -> str | None:
    if not isinstance(value, str):
        errors.append({"field": "password", "code": "invalid_type", "message": "Password must be a string."})
        return None

    password = value
    password_norm = unicodedata.normalize("NFKC", password)
    password_fold = password_norm.casefold()

    if len(password) < MIN_PASSWORD_LEN:
        errors.append({"field": "password", "code": "too_short", "message": f"Password must be at least {MIN_PASSWORD_LEN} characters."})

    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        errors.append({"field": "password", "code": "too_long", "message": "Password is too long."})
        return password

    if CONTROL_OR_INVISIBLE_RE.search(password):
        errors.append({"field": "password", "code": "invalid_characters", "message": "Password contains control or invisible characters."})

    if password != password.strip():
        errors.append({"field": "password", "code": "surrounding_whitespace", "message": "Password must not start or end with whitespace."})

    classes = [
        any(c.islower() for c in password),
        any(c.isupper() for c in password),
        any(c.isdigit() for c in password),
        any(c in string.punctuation or (not c.isalnum() and not c.isspace()) for c in password),
    ]
    if sum(classes) < 3:
        errors.append({"field": "password", "code": "insufficient_complexity", "message": "Password must include at least three character classes."})

    if estimated_entropy_bits(password) < 50:
        errors.append({"field": "password", "code": "low_entropy", "message": "Password is too predictable."})

    if password_fold in COMMON_PASSWORDS:
        errors.append({"field": "password", "code": "common_password", "message": "Password is too common."})

    if re.search(r"(.)\1{4,}", password_fold):
        errors.append({"field": "password", "code": "repeated_characters", "message": "Password contains too many repeated characters."})

    if contains_sequence(password_fold):
        errors.append({"field": "password", "code": "sequential_characters", "message": "Password contains an obvious sequence."})

    comparison_tokens = set()
    if username_norm:
        comparison_tokens.add(username_norm)
    if email_norm and "@" in email_norm:
        local, domain = email_norm.split("@", 1)
        comparison_tokens.update({email_norm.casefold(), local.casefold(), domain.split(".")[0].casefold()})
    if display_name:
        comparison_tokens.update(
            token.casefold()
            for token in re.split(r"[^A-Za-z0-9]+", html.unescape(display_name))
            if len(token) >= 3
        )

    for token in comparison_tokens:
        if len(token) >= 3 and token in password_fold:
            errors.append({"field": "password", "code": "contains_personal_info", "message": "Password must not contain account identifiers."})
            break
        if len(token) >= 6 and SequenceMatcher(None, token, password_fold).ratio() >= 0.72:
            errors.append({"field": "password", "code": "similar_to_identifier", "message": "Password is too similar to account identifiers."})
            break

    return password


def enforce_csrf_and_origin(request: Request) -> JSONResponse | None:
    origin = request.headers.get("origin")
    sec_fetch_site = request.headers.get("sec-fetch-site", "").lower()

    if sec_fetch_site == "cross-site":
        return error_response(
            status.HTTP_403_FORBIDDEN,
            [{"field": "headers", "code": "cross_site_forbidden", "message": "Cross-site registration requests are not allowed."}],
        )

    if origin and ALLOWED_ORIGINS and origin not in ALLOWED_ORIGINS:
        return error_response(
            status.HTTP_403_FORBIDDEN,
            [{"field": "headers", "code": "origin_forbidden", "message": "Origin is not allowed."}],
        )

    if request.headers.get("cookie"):
        header_token = request.headers.get("x-csrf-token", "")
        cookie_token = request.cookies.get("csrf_token", "")
        if not header_token or not cookie_token or not hmac.compare_digest(header_token, cookie_token):
            return error_response(
                status.HTTP_403_FORBIDDEN,
                [{"field": "headers", "code": "csrf_failed", "message": "CSRF validation failed."}],
            )

    return None


async def hibp_pwned_password_count(password: str) -> int:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]
    now = time.time()

    cached = hibp_cache.get(prefix)
    if cached and cached[0] > now:
        return cached[1] if cached[1] == suffix else 0

    async with httpx.AsyncClient(timeout=2.5) as client:
        response = await client.get(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            headers={
                "User-Agent": "registration-service/1.0",
                "Add-Padding": "true",
            },
        )
        response.raise_for_status()

    count = 0
    for line in response.text.splitlines():
        try:
            returned_suffix, returned_count = line.split(":", 1)
        except ValueError:
            continue
        if hmac.compare_digest(returned_suffix.upper(), suffix):
            count = int(returned_count)
            break

    hibp_cache[prefix] = (now + 6 * 60 * 60, suffix if count else "")
    return count


def init_db() -> None:
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA foreign_keys=ON")
        conn.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email TEXT NOT NULL,
                email_normalized TEXT NOT NULL UNIQUE,
                username TEXT NOT NULL,
                username_normalized TEXT NOT NULL UNIQUE,
                display_name TEXT NOT NULL,
                password_hash TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            )
        """)
        conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_users_email_norm ON users(email_normalized)")
        conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_users_username_norm ON users(username_normalized)")


def insert_user(cleaned: CleanRegistration, password_hash: str) -> bool:
    with sqlite3.connect(DB_PATH, timeout=5) as conn:
        conn.execute("PRAGMA foreign_keys=ON")
        cursor = conn.execute(
            """
            INSERT OR IGNORE INTO users
                (email, email_normalized, username, username_normalized, display_name, password_hash)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                cleaned.email,
                cleaned.email_normalized,
                cleaned.username,
                cleaned.username_normalized,
                cleaned.display_name,
                password_hash,
            ),
        )
        conn.commit()
        return cursor.rowcount == 1


def hash_password(password: str) -> str:
    pepper = os.getenv("PASSWORD_PEPPER", "")
    return ARGON2.hash(password + pepper)


def error_response(http_status: int, errors: list[dict[str, str]]) -> JSONResponse:
    return JSONResponse(status_code=http_status, content={"ok": False, "errors": errors})


def rate_limit_response(retry_after: int) -> JSONResponse:
    response = error_response(
        status.HTTP_429_TOO_MANY_REQUESTS,
        [{"field": "request", "code": "rate_limited", "message": "Too many registration attempts."}],
    )
    response.headers["Retry-After"] = str(retry_after)
    return response


def get_client_ip(request: Request) -> str:
    if TRUST_PROXY_HEADERS:
        forwarded = request.headers.get("x-forwarded-for", "")
        if forwarded:
            return forwarded.split(",", 1)[0].strip()
    return request.client.host if request.client else "unknown"


def rate_key(value: str) -> str:
    return hmac.new(APP_SECRET.encode(), value.encode(), hashlib.sha256).hexdigest()


def rough_email_key(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    rough = unicodedata.normalize("NFKC", value.strip()).casefold()
    return rough[:254] if rough else None


def domain_is_blocked(domain: str, blocked: set[str]) -> bool:
    labels = domain.casefold().split(".")
    return any(".".join(labels[i:]) in blocked for i in range(len(labels)))


def username_skeleton(value: str) -> str:
    table = str.maketrans({"0": "o", "1": "l", "3": "e", "4": "a", "5": "s", "7": "t"})
    return re.sub(r"[^a-z0-9]", "", value.casefold().translate(table))


def constant_time_member(value: str, candidates: set[str]) -> bool:
    return any(hmac.compare_digest(value, candidate) for candidate in candidates)


def password_too_large(password: str) -> bool:
    return len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES


def contains_sequence(value: str) -> bool:
    sequences = [
        "abcdefghijklmnopqrstuvwxyz",
        "0123456789",
        "qwertyuiop",
        "asdfghjkl",
        "zxcvbnm",
    ]
    for seq in sequences:
        for candidate in (seq, seq[::-1]):
            for i in range(0, len(candidate) - 3):
                if candidate[i:i + 4] in value:
                    return True
    return False


def estimated_entropy_bits(password: str) -> float:
    pool = 0
    if any(c.islower() for c in password):
        pool += 26
    if any(c.isupper() for c in password):
        pool += 26
    if any(c.isdigit() for c in password):
        pool += 10
    if any(c in string.punctuation for c in password):
        pool += len(string.punctuation)
    if any(ord(c) > 127 for c in password):
        pool += 64
    return len(password) * math.log2(max(pool, 1))


async def sleep_until_minimum(started: float) -> None:
    remaining = MIN_VALID_RESPONSE_SECONDS - (time.monotonic() - started)
    if remaining > 0:
        await asyncio.sleep(remaining)
